import {
  Flex,
  FlexItem,
  Card,
  CardHeader,
  CardTitle,
  CardBody,
  Badge,
  Content,
} from '@patternfly/react-core';
import { KanbanCard } from './KanbanCard';
import type { Feature } from '../state/store';

export interface KanbanBoardProps {
  features: Feature[];
}

// Column definitions with status mapping
const COLUMNS = [
  { id: 'backlog', title: 'BACKLOG', statuses: ['backlog'] },
  { id: 'todo', title: 'TODO', statuses: ['todo', 'pending'] },
  { id: 'doing', title: 'DOING', statuses: ['doing', 'in_progress', 'wip'] },
  { id: 'review', title: 'REVIEW', statuses: ['review', 'pr'] },
  { id: 'qa', title: 'QA', statuses: ['qa', 'testing'] },
  { id: 'done', title: 'DONE', statuses: ['done', 'completed', 'passed'] },
] as const;

// Map feature to column based on status and passes flag
function getColumnForFeature(feature: Feature): string {
  // If feature passes, it's DONE regardless of status
  if (feature.passes) {
    return 'done';
  }

  const status = feature.status.toLowerCase();

  for (const column of COLUMNS) {
    if (column.statuses.some((s) => status.includes(s))) {
      return column.id;
    }
  }

  // Default to backlog if status not recognized
  return 'backlog';
}

// Group features by column
function groupByColumn(features: Feature[]): Record<string, Feature[]> {
  const grouped: Record<string, Feature[]> = {};

  // Initialize all columns
  for (const column of COLUMNS) {
    grouped[column.id] = [];
  }

  // Sort features into columns
  for (const feature of features) {
    const columnId = getColumnForFeature(feature);
    grouped[columnId].push(feature);
  }

  // Sort features within each column by priority
  const priorityOrder: Record<string, number> = {
    critical: 0,
    high: 1,
    medium: 2,
    low: 3,
  };

  for (const columnId of Object.keys(grouped)) {
    grouped[columnId].sort((a, b) => {
      const aPriority = priorityOrder[a.priority] ?? 4;
      const bPriority = priorityOrder[b.priority] ?? 4;
      return aPriority - bPriority;
    });
  }

  return grouped;
}

const columnStyles: React.CSSProperties = {
  minWidth: '220px',
  maxWidth: '280px',
  flex: '1 1 220px',
  height: '100%',
  display: 'flex',
  flexDirection: 'column',
};

const columnHeaderStyles: React.CSSProperties = {
  backgroundColor: '#f0f0f0',
  borderBottom: '2px solid #06c',
};

const columnBodyStyles: React.CSSProperties = {
  backgroundColor: '#fafafa',
  flex: 1,
