} from '@patternfly/react-core';
import { TabBar, KanbanBoard, LogPanel, TerminalPanel } from './components';
import type { LogEntry } from './components';
import type { Project, Feature } from './state/store';

// Mock projects for demonstration
const createMockProject = (id: string, name: string): Project => ({
