//! Dev Bridge - Secure RPC bridge for browser-to-native communication
//!
//! This module provides a development-only WebSocket server that mirrors Tauri commands,
//! allowing Playwright and other browser-based tools to interact with native features.
//!
//! SECURITY:
//! - Only compiled in debug mode (#[cfg(debug_assertions)])
//! - localhost-only binding (127.0.0.1)
//! - Token-based authentication
//! - Command allowlist (no arbitrary execution)

#![cfg(debug_assertions)]

use crate::pty::{PtyManager, ProcessInfo};
use axum::{
    extract::{
        ws::{Message, WebSocket, WebSocketUpgrade},
        Query, State,
    },
    http::StatusCode,
    response::{IntoResponse, Response},
    routing::get,
    Router,
};
use futures_util::{SinkExt, StreamExt};
use parking_lot::Mutex;
use serde::{Deserialize, Serialize};
use std::sync::Arc;
use tokio::sync::broadcast;
use tower_http::cors::{Any, CorsLayer};

/// Default port for dev bridge server
const DEFAULT_PORT: u16 = 9876;

/// RPC Request format
#[derive(Debug, Deserialize)]
pub struct RpcRequest {
    /// Unique request ID for response correlation
    pub id: String,
    /// Command name (e.g., "pty_spawn", "pty_write")
    pub cmd: String,
    /// Command arguments as JSON
    #[serde(default)]
    pub args: serde_json::Value,
}

/// RPC Response format
#[derive(Debug, Serialize)]
pub struct RpcResponse {
    /// Request ID for correlation
    pub id: String,
    /// Success flag
    pub success: bool,
    /// Result data (if success)
    #[serde(skip_serializing_if = "Option::is_none")]
    pub result: Option<serde_json::Value>,
    /// Error message (if failure)
    #[serde(skip_serializing_if = "Option::is_none")]
    pub error: Option<String>,
}

/// Event broadcast to clients
#[derive(Debug, Clone, Serialize)]
pub struct RpcEvent {
    /// Event type (e.g., "pty-output", "pty-exit")
    pub event: String,
    /// Event payload
    pub payload: serde_json::Value,
}

/// Query params for auth
#[derive(Debug, Deserialize)]
pub struct AuthQuery {
    pub token: Option<String>,
}

/// Dev Bridge server state
pub struct DevBridgeState {
    /// Auth token (generated at startup)
    pub token: String,
    /// PTY manager reference
    pub pty_manager: Arc<PtyManager>,
    /// Event broadcaster
    pub event_tx: broadcast::Sender<RpcEvent>,
    /// Connected clients count
    pub clients: Mutex<u32>,
}

impl DevBridgeState {
    pub fn new(pty_manager: Arc<PtyManager>) -> Self {
        let (event_tx, _) = broadcast::channel(1024);

        // Generate random token
        let token: String = (0..32)
            .map(|_| {
                let idx = rand::random::<u8>() % 62;
                let c = if idx < 10 {
                    (b'0' + idx) as char
                } else if idx < 36 {
                    (b'A' + idx - 10) as char
                } else {
                    (b'a' + idx - 36) as char
                };
                c
            })
            .collect();

        Self {
            token,
            pty_manager,
            event_tx,
            clients: Mutex::new(0),
        }
    }

    /// Broadcast an event to all connected clients
    pub fn broadcast(&self, event: RpcEvent) {
        let _ = self.event_tx.send(event);
    }
}

/// Start the dev bridge server
///
/// Returns the auth token and a handle to the server task
pub async fn start_dev_bridge(
    pty_manager: Arc<PtyManager>,
    port: Option<u16>,
) -> (String, tokio::task::JoinHandle<()>) {
    let port = port.unwrap_or(DEFAULT_PORT);
    let state = Arc::new(DevBridgeState::new(pty_manager));
    let token = state.token.clone();

    let cors = CorsLayer::new()
        .allow_origin(Any)
        .allow_methods(Any)
        .allow_headers(Any);

    let app = Router::new()
        .route("/health", get(health_check))
        .route("/ws", get(ws_handler))
        .layer(cors)
        .with_state(state);

    let addr = format!("127.0.0.1:{}", port);

    println!("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");
    println!("🌉 DEV BRIDGE ACTIVE (debug mode only)");
    println!("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");
    println!("   Address: http://{}", addr);
    println!("   Token:   {}", token);
    println!("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");

    // Write token to file for frontend to read
    let token_path = std::env::temp_dir().join("hq-dev-bridge-token");
    if let Err(e) = std::fs::write(&token_path, &token) {
        eprintln!("Warning: Could not write token file: {}", e);
    } else {
        println!("   Token file: {:?}", token_path);
    }

    let listener = tokio::net::TcpListener::bind(&addr)
        .await
        .expect("Failed to bind dev bridge server");

    let handle = tokio::spawn(async move {
        axum::serve(listener, app).await.unwrap();
    });

    (token, handle)
}

/// Health check endpoint
async fn health_check() -> &'static str {
    "HQ Dev Bridge OK"
}

/// WebSocket handler with auth
async fn ws_handler(
    ws: WebSocketUpgrade,
    Query(query): Query<AuthQuery>,
    State(state): State<Arc<DevBridgeState>>,
) -> Response {
    // Validate token
    match query.token {
        Some(token) if token == state.token => {
            ws.on_upgrade(move |socket| handle_socket(socket, state))
        }
        _ => (StatusCode::UNAUTHORIZED, "Invalid or missing token").into_response(),
    }
}

/// Handle WebSocket connection
async fn handle_socket(socket: WebSocket, state: Arc<DevBridgeState>) {
    let (mut sender, mut receiver) = socket.split();

    // Increment client count
    {
        let mut clients = state.clients.lock();
        *clients += 1;
        println!("Dev Bridge: Client connected (total: {})", *clients);
